"use client";
import { useEffect, useState } from "react";
import { Clock, Plus, CheckCircle, XCircle } from "lucide-react";
import { motion } from "framer-motion";
import { formatDate } from "@/lib/utils";

interface HoursLog { id: string; date: string; hours: number; status: string; notes: string | null; assignment: { need: { title: string } } | null }

export default function HoursPage() {
  const [logs, setLogs] = useState<HoursLog[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetch("/api/hours").then(r => r.json()).then(d => { setLogs(Array.isArray(d) ? d : []); setLoading(false); });
  }, []);

  return (
    <div className="max-w-4xl mx-auto space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold flex items-center gap-2" style={{ fontFamily: "Plus Jakarta Sans", color: "var(--ink)" }}>
            <Clock size={28} style={{ color: "var(--green-dark)" }} /> Hours Tracking
          </h1>
          <p className="text-sm mt-1" style={{ color: "var(--muted)" }}>Log and track your volunteer hours</p>
        </div>
        <button className="flex items-center gap-2 px-4 py-2 rounded-xl text-white font-medium text-sm" style={{ background: "var(--green-dark)" }}>
          <Plus size={16} /> Log Hours
        </button>
      </div>

      <div className="glass rounded-2xl overflow-hidden">
        <div className="px-6 py-4 border-b" style={{ borderColor: "var(--green-pale)" }}>
          <h2 className="font-bold" style={{ fontFamily: "Plus Jakarta Sans", color: "var(--ink)" }}>My Hours Log</h2>
        </div>
        {loading ? (
          <div className="p-8 text-center text-sm" style={{ color: "var(--muted)" }}>Loading…</div>
        ) : logs.length === 0 ? (
          <div className="p-12 text-center">
            <Clock size={36} className="mx-auto mb-3" style={{ color: "var(--muted)" }} />
            <p className="font-bold" style={{ color: "var(--ink)" }}>No hours logged yet</p>
            <p className="text-sm" style={{ color: "var(--muted)" }}>Start logging your volunteer hours to earn points and badges.</p>
          </div>
        ) : (
          <div className="divide-y" style={{ divideColor: "var(--green-pale)" }}>
            {logs.map((log, i) => (
              <motion.div key={log.id} initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ delay: i * 0.05 }}
                className="flex items-center gap-4 px-6 py-4">
                <div className="w-10 h-10 rounded-xl flex items-center justify-center" style={{ background: "var(--green-pale)" }}>
                  <Clock size={18} style={{ color: "var(--green-dark)" }} />
                </div>
                <div className="flex-1">
                  <p className="font-medium text-sm" style={{ color: "var(--ink)" }}>{log.assignment?.need?.title ?? "General Volunteering"}</p>
                  <p className="text-xs mt-0.5" style={{ color: "var(--muted)" }}>{formatDate(log.date)} · {log.notes ?? "No notes"}</p>
                </div>
                <div className="text-right">
                  <div className="font-bold text-lg" style={{ color: "var(--green-dark)" }}>{log.hours}h</div>
                  <span className={`text-xs font-semibold px-2 py-0.5 rounded-full ${log.status === "APPROVED" ? "badge-low" : log.status === "REJECTED" ? "badge-critical" : "badge-medium"}`}>
                    {log.status}
                  </span>
                </div>
              </motion.div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
